def as_relationship_signal(km):
    if km is None:
        return {"signal": 0.0, "note": "missing geo"}
    if km <= 2.0:
        return {"signal": 0.7, "note": "geoseñal de relación, no un veredicto"}
    return {"signal": 0.1, "note": "distante"}

print(as_relationship_signal(1.2))
